import{_ as a,r,o as d,c as s,a as e,b as n,e as l,d as t}from"./app-3aae6edf.js";const c={},o=e("h1",{id:"利用多台-mysql-服务器产生分布式-id",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#利用多台-mysql-服务器产生分布式-id","aria-hidden":"true"},"#"),n(" 利用多台 MySQL 服务器产生分布式 id")],-1),u=e("p",null,"MySQL 可以产生自增ID，利用多台 MySQL 服务器也可以组成一个高性能的分布式发号器。",-1),m=e("p",null,"假设用 8 台 MySQL 服务器协同工作，第一台 MySQL 初始值是1，每次自增8，第二台 MySQL 初始值是 2，每次自增 8，依次类推。前面用一个 round-robin load balancer 挡着，每来一个请求，由 round-robin balancer 随机地将请求发给 8 台 MySQL 中的任意一个，然后返回一个 ID。",-1),v={href:"https://code.flickr.net/2010/02/08/ticket-servers-distributed-unique-primary-keys-on-the-cheap/",target:"_blank",rel:"noopener noreferrer"},_=t('<p>该方案的缺点是缺点是 ID 是不是严格递增的，只是粗略递增的。</p><h2 id="创建数据表数据表" tabindex="-1"><a class="header-anchor" href="#创建数据表数据表" aria-hidden="true">#</a> 创建数据表数据表</h2><div class="language-SQL line-numbers-mode" data-ext="SQL"><pre class="language-SQL"><code>CREATE TABLE `tbl_name` {\n    `id` BIGINT(20) UNSIGNED NOT NULL AUTO_INCREMENT,\n    `row_name` char(1) NOT NULL DEFAULT &#39;&#39;,\n    PRIMARY KEY (`id`),\n    UNIQUE KEY `row_name` (`row_name`)\n} ENGINE=InnoDB\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>每次我们想要生成并获取 id 时。利用 REPLACE INTO 生成新的 ID。执行如下所示</p><div class="language-SQL line-numbers-mode" data-ext="SQL"><pre class="language-SQL"><code>REPLACE INTO `tbl_name` (`row_name`) VALUES (&#39;a&#39;)\nSELECT LAST_INSERT_ID()\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>auto_increment_offset表示自增长字段从那个数开始，他的取值范围是1 .. 65535</li><li>auto_increment_increment表示自增长字段每次递增的量，其默认值是1，取值范围是1 .. 65535</li></ul><p>如果有两台服务器设定如下所示</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>Server 1:\nauto-increment-increment = 2\nauto-increment-offset = 1\n\nServer 2:\nauto-increment-increment = 2\nauto-increment-offset = 2\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div>',8);function b(h,L){const i=r("ExternalLinkIcon");return d(),s("div",null,[o,u,m,e("p",null,[e("a",v,[n("Flickr 票务服务使用了这中方案"),l(i)]),n("。Flickr 票务服务器是一个专用的数据库服务器，上面只有一个数据库，在该数据库中有用于 32 位 ID 数据表 Tickets32 和用于 64 位 ID 的数据表 Tickets64。")]),_])}const E=a(c,[["render",b],["__file","uid.html.vue"]]);export{E as default};
